function dmg(l){return[0,0,0,10,26,55,90,140,200][Math.min(l,8)]||200}
function tier(l){if(l<=3)return{t:"Fizzle",c:"tier0"};if(l==4)return{t:"Minor bolt",c:"tier1"};if(l==5)return{t:"Power surge",c:"tier2"};if(l==6)return{t:"CRITICAL!",c:"tier3"};return{t:"LEGENDARY!",c:"tier4"}}
function shuf(a){const b=[...a];for(let i=b.length-1;i>0;i--){const j=0|Math.random()*(i+1);[b[i],b[j]]=[b[j],b[i]]}return b}
function mkTiles(L){return shuf(L).map((l,i)=>({id:i,letter:l}))}
function hpCol(p){return p>55?"#22c55e":p>28?"#f59e0b":"#ef4444"}

// ── Audio ──────────────────────────────────────────────────────
let A=null, musicTimer=null, muted=false, musicStep=0, currentTheme=null;

function ensureAudio(){
  if(!A){try{A=new(window.AudioContext||window.webkitAudioContext)()}catch(e){return false}}
  if(A.state==='suspended')A.resume();
  return true;
}
function tone(freq,dur,type='square',vol=0.08,delay=0){
  if(muted||!A||freq<=0)return;
  const o=A.createOscillator(),g=A.createGain();
  o.type=type;o.frequency.value=freq;
  const t=A.currentTime+delay;
  g.gain.setValueAtTime(0.0001,t);
  g.gain.exponentialRampToValueAtTime(vol,t+0.008);
  g.gain.exponentialRampToValueAtTime(0.0001,t+dur);
  o.connect(g).connect(A.destination);
  o.start(t);o.stop(t+dur+0.02);
}
function noise(dur,vol=0.1,filter=1200,delay=0){
  if(muted||!A)return;
  const buf=A.createBuffer(1,A.sampleRate*dur,A.sampleRate);
  const d=buf.getChannelData(0);
  for(let i=0;i<d.length;i++)d[i]=(Math.random()*2-1)*Math.pow(1-i/d.length,1.5);
  const s=A.createBufferSource(),g=A.createGain(),f=A.createBiquadFilter();
  f.type='lowpass';f.frequency.value=filter;
  s.buffer=buf;g.gain.value=vol;
  s.connect(f).connect(g).connect(A.destination);
  s.start(A.currentTime+delay);
}

const THEMES={battle:{bpm:130,steps:[
  [110,0,'k'],[0,0,null],[0,659,null],[0,0,null],
  [110,784,null],[0,0,null],[165,0,'s'],[0,659,null],
  [110,0,'k'],[0,587,null],[0,0,null],[0,659,null],
  [82,784,null],[0,0,null],[165,0,'s'],[0,1047,null],
  [110,0,'k'],[0,0,null],[0,784,null],[0,0,null],
  [110,659,null],[0,0,null],[165,0,'s'],[0,587,null],
  [110,0,'k'],[0,523,null],[0,659,null],[0,0,null],
  [82,587,null],[0,0,null],[165,0,'s'],[0,659,null]
]}};

function startMusic(theme){
  stopMusic();
  if(muted||!ensureAudio())return;
  currentTheme=theme;
  if(theme==='battle'){
    musicStep=0;
    const pat=THEMES.battle.steps;
    const interval=60000/THEMES.battle.bpm/2;
    const play=()=>{
      if(muted||currentTheme!=='battle'){stopMusic();return}
      const[b,l,d]=pat[musicStep%pat.length];
      if(b>0)tone(b,0.25,'triangle',0.09);
      if(l>0)tone(l,0.18,'square',0.045);
      if(d==='k'){noise(0.1,0.12,180);tone(60,0.1,'sine',0.15)}
      if(d==='s')noise(0.08,0.08,5000);
      musicStep++;
    };
    play();
    musicTimer=setInterval(play,interval);
  }
  else if(theme==='victory'){
    const n=[523,659,784,1047,784,1047,1319,1568];
    n.forEach((f,i)=>{tone(f,0.22,'square',0.1,i*0.11);tone(f/2,0.22,'triangle',0.08,i*0.11)});
    [523,659,784,1047].forEach(f=>{tone(f,2,'square',0.07,1.1);tone(f,2,'triangle',0.04,1.1)});
    noise(0.15,0.12,8000,1.0);
  }
  else if(theme==='defeat'){
    const n=[440,392,349,330,294,220];
    n.forEach((f,i)=>{tone(f,0.9,'sine',0.11,i*0.55);tone(f/2,0.9,'triangle',0.07,i*0.55);tone(f*1.2,0.7,'sine',0.04,i*0.55+0.1)});
  }
  else if(theme==='complete'){
    const n=[261,329,392,523,659,784,1047];
    n.forEach((f,i)=>{tone(f,0.3,'square',0.11,i*0.13);tone(f/2,0.3,'triangle',0.09,i*0.13)});
    [523,659,784,1047,1319].forEach(f=>{tone(f,3,'square',0.06,0.95);tone(f,3,'sine',0.04,0.95)});
  }
}
function stopMusic(){if(musicTimer)clearInterval(musicTimer);musicTimer=null;currentTheme=null}

function sfxTap(){tone(880,0.04,'square',0.05);tone(1760,0.03,'square',0.03,0.01)}
function sfxDeselect(){tone(440,0.04,'square',0.04)}
function sfxCast(len){for(let i=0;i<Math.min(len,8);i++){tone(330+i*80,0.09,'square',0.07,i*0.04);tone(660+i*160,0.07,'triangle',0.04,i*0.04)}}
function sfxHit(big){
  if(big){tone(120,0.3,'square',0.13);tone(180,0.3,'sawtooth',0.09,0.02);noise(0.35,0.2,1500);tone(880,0.15,'square',0.08,0.05)}
  else{tone(160,0.15,'square',0.1);noise(0.15,0.13,1000)}
}
function sfxPlayerHurt(){noise(0.22,0.15,2400);tone(200,0.18,'sawtooth',0.1);tone(150,0.2,'square',0.08,0.02)}
function sfxInvalid(){tone(220,0.08,'sawtooth',0.07);tone(196,0.12,'sawtooth',0.06,0.05)}

