function getSprite(mi,h){return[goblinSVG,golemSVG,dragonSVG][mi](h)}

// ── Event delegation ───────────────────────────────────────────
document.addEventListener('click',e=>{
  const el=e.target.closest('[data-a]');if(!el)return;
  const a=el.dataset.a,p=el.dataset.p;
  if(a==='tile')tapTile(+p);
  else if(a==='cast')castSpell();
  else if(a==='clear')clearWord();
  else if(a==='next')nextMonster();
  else if(a==='restart')restartGame();
  else if(a==='sound')toggleSound();
});

function toggleSound(){
  muted=!muted;
  const b=document.getElementById('sbtn');
  if(b)b.textContent=muted?'\u266A\u0338':'\u266A';
  if(muted)stopMusic();
  else{ensureAudio();if(S.phase==='battle')startMusic('battle')}
}

// ── Timers ─────────────────────────────────────────────────────
function startTimers(){
  clearInterval(atkT);clearInterval(progT);atkElapsed=0;
  const m=MONSTERS[S.mi];
  progT=setInterval(()=>{
    if(S.phase!=='battle')return;
    atkElapsed+=100;
    const pct=Math.min(100,atkElapsed/m.iv*100);
    const bar=document.getElementById('atkb');
    if(bar)bar.style.width=pct+'%';
  },100);
  atkT=setInterval(()=>{
    if(S.phase!=='battle'||S.dying)return;
    atkElapsed=0;
    setSpriteState('s-wind');
    setTimeout(()=>{
      if(S.phase!=='battle')return;
      setSpriteState('s-atk');
      setTimeout(()=>{
        if(S.phase!=='battle')return;
        S.php=Math.max(0,S.php-m.atk);
        S.phurt=true;
        flash('red');
        sfxPlayerHurt();
        addFloat(`-${m.atk}`,'#ef4444',22,25+Math.random()*40,150);
        addLog(`${m.name} lunges — ${m.atk} damage!`);
        setTimeout(()=>{S.phurt=false;const pb=document.getElementById('pbar');if(pb)pb.classList.remove('phurt')},380);
        if(S.php<=0){goDefeat();return}
        renderBattle();
      },220);
      setTimeout(()=>{setSpriteState('')},600);
    },280);
  },m.iv);
}
function stopTimers(){clearInterval(atkT);clearInterval(progT)}

function setSpriteState(cls){
  const s=document.getElementById('sprite');
  if(!s)return;
  const m=MONSTERS[S.mi];
  s.className='sprite '+m.sclass+(cls?' '+cls:'');
}

// ── Effects ────────────────────────────────────────────────────
function flash(color){
  const f=document.getElementById('flash');
  if(!f)return;
  f.className='flash on '+(color||'');
  setTimeout(()=>{f.className='flash'},120);
}
function addFloat(text,color,size,x,yOffset){
  const fx=document.getElementById('fxlayer');
  if(!fx)return;
  const el=document.createElement('div');
  el.className='fdmg';
  el.style.cssText=`left:${x}%;bottom:${yOffset||180}px;font-size:${size}px;color:${color}`;
  el.textContent=text;
  fx.appendChild(el);
  setTimeout(()=>el.remove(),1500);
}
function sparkBurst(x,y,color,count){
  const fx=document.getElementById('fxlayer');
  if(!fx)return;
  for(let i=0;i<count;i++){
    const p=document.createElement('div');
    p.className='part';
    const angle=(i/count)*Math.PI*2+Math.random()*.5;
    const dist=40+Math.random()*60;
    const size=3+Math.random()*5;
    p.style.cssText=`left:${x}px;top:${y}px;width:${size}px;height:${size}px;background:${color};box-shadow:0 0 10px ${color};--bx:${Math.cos(angle)*dist}px;--by:${Math.sin(angle)*dist}px`;
    fx.appendChild(p);
    setTimeout(()=>p.remove(),850);
  }
}
function projectile(fromX,fromY,toX,toY,color){
  const fx=document.getElementById('fxlayer');
  if(!fx)return;
  const p=document.createElement('div');
  p.className='proj';
  p.style.cssText=`left:${fromX}px;top:${fromY}px;background:${color};color:${color};--tx:${toX-fromX}px;--ty:${toY-fromY}px`;
  fx.appendChild(p);
  setTimeout(()=>p.remove(),480);
}
function impactBurst(x,y,color){
  const fx=document.getElementById('fxlayer');
  if(!fx)return;
  const el=document.createElement('div');
  el.className='impact';
  el.style.cssText=`left:${x-40}px;top:${y-40}px;--ic:${color}`;
  fx.appendChild(el);
  setTimeout(()=>el.remove(),500);
}
function tileSparkle(tileId){
  const fx=document.getElementById('fxlayer');
  const btn=document.querySelector(`[data-a="tile"][data-p="${tileId}"]`);
  if(!btn||!fx)return;
  const r=btn.getBoundingClientRect(),fr=fx.getBoundingClientRect();
  for(let i=0;i<3;i++){
    const s=document.createElement('div');
    s.className='spark';
    s.style.cssText=`left:${r.left-fr.left+r.width/2+(Math.random()*20-10)}px;top:${r.top-fr.top+10}px;color:#fbbf24;background:#fbbf24`;
    fx.appendChild(s);
    setTimeout(()=>s.remove(),1200);
  }
}

// ── Logic ──────────────────────────────────────────────────────
function addLog(t){S.log=[t,...S.log].slice(0,4)}
function canMake(w,letters){const a=[...letters];for(const c of w.toUpperCase()){const i=a.indexOf(c);if(i<0)return false;a.splice(i,1)}return true}

function tapTile(id){
  if(S.phase!=='battle')return;
  ensureAudio();
  if(S.sel.includes(id)){S.sel=S.sel.filter(x=>x!==id);sfxDeselect()}
  else{S.sel=[...S.sel,id];sfxTap();tileSparkle(id)}
  renderBattle();
}
function clearWord(){if(S.phase!=='battle')return;S.sel=[];sfxDeselect();renderBattle()}
function castSpell(){
  if(S.phase!=='battle'||S.dying)return;
  ensureAudio();
  const m=MONSTERS[S.mi];
  const word=S.sel.map(id=>{const t=S.tiles.find(t=>t.id===id);return t?t.letter:''}).join('').toLowerCase();
  if(word.length<3){addLog('Need at least 3 letters!');sfxInvalid();renderBattle();return}
  if(S.used.has(word)){addLog(`"${word.toUpperCase()}" already cast.`);S.sel=[];sfxInvalid();renderBattle();return}
  if(!W.has(word)){addLog(`"${word.toUpperCase()}" — not a valid word!`);S.sel=[];sfxInvalid();renderBattle();return}
  const d=dmg(word.length);
  const cb=S.combo>=2?Math.round(d*.25):0;
  const total=d+cb;
  S.combo++;S.used.add(word);S.sel=[];S.tiles=mkTiles(m.tiles);S.mhp=Math.max(0,S.mhp-total);
  const big=word.length>=6;
  sfxCast(word.length);
  setTimeout(()=>{
    sfxHit(big);
    if(big)flash('gold');
    const arena=document.getElementById('arena');
    if(arena){
      const r=arena.getBoundingClientRect(),fx=document.getElementById('fxlayer');
      const fr=fx.getBoundingClientRect();
      const cx=r.left-fr.left+r.width/2,cy=r.top-fr.top+r.height*.55;
      const col=word.length>=7?'#a78bfa':word.length===6?'#f97316':word.length===5?'#fbbf24':'#60a5fa';
      projectile(cx,cy+100,cx,cy,col);
      setTimeout(()=>{
        impactBurst(cx,cy,col);
        sparkBurst(cx,cy,col,big?14:8);
        addFloat(`${big?'⚡ ':''}${total}`,col,big?30:24,18+Math.random()*50,150);
        setSpriteState('s-hurt');
        const a=document.getElementById('arena');
        if(a&&big){a.classList.add('shaking');setTimeout(()=>a.classList.remove('shaking'),400)}
        setTimeout(()=>setSpriteState(''),550);
        renderBattle();
      },400);
    }
  },word.length*40+50);
  const tv=tier(word.length);
  let msg=`${tv.t} "${word.toUpperCase()}" → ${total} dmg`;
  if(cb>0)msg+=` (×${S.combo} combo!)`;
  addLog(msg);
  if(S.mhp<=0){
    S.dying=true;S.txp+=m.xp;
    setTimeout(()=>{
      setSpriteState('s-die');
      setTimeout(()=>{
        stopTimers();
        if(S.mi<MONSTERS.length-1){goTransition()}
        else{goComplete()}
      },900);
    },500);
  }
  renderBattle();
}

function goTransition(){S.phase='transition';stopMusic();showScreen('sTrans',renderTransition());startMusic('victory')}
function goComplete(){S.phase='complete';stopMusic();showScreen('sWin',renderComplete());startMusic('complete')}
function goDefeat(){S.phase='defeat';stopMusic();stopTimers();showScreen('sDefeat',renderDefeat());startMusic('defeat')}
function nextMonster(){
  stopMusic();
  S.mi++;const m=MONSTERS[S.mi];
  S.mhp=m.maxHp;S.php=100;S.tiles=mkTiles(m.tiles);S.sel=[];S.used=new Set();S.combo=0;
  S.log=[`A ${m.name} emerges!`];S.phase='battle';S.dying=false;
  showScreen('sBattle',buildBattleHTML());
  renderBattle();startTimers();
  startMusic('battle');
}
function restartGame(){
  stopMusic();stopTimers();
  S={phase:'battle',mi:0,mhp:MONSTERS[0].maxHp,php:100,tiles:mkTiles(MONSTERS[0].tiles),sel:[],used:new Set(),log:['The dungeon awakens. Spell words to attack!'],combo:0,phurt:false,txp:0,dying:false};
  showScreen('sBattle',buildBattleHTML());
  renderBattle();startTimers();
  startMusic('battle');
}

// ── Rendering ──────────────────────────────────────────────────
function showScreen(id,html){
  document.querySelectorAll('.screen').forEach(s=>s.classList.remove('on'));
  const el=document.getElementById(id);
  if(el){el.innerHTML=html;setTimeout(()=>el.classList.add('on'),20)}
}
function buildBattleHTML(){
  const m=MONSTERS[S.mi];
  return `
  <div class="bg">${getBG(m.scene)}</div>
  <div class="title" style="color:${m.acc}">✦ Spell Forge ✦</div>
  <div class="battle-ui" id="battleUI"></div>
  <div class="fx" id="fxlayer"></div>`;
}
function renderBattle(){
  const ui=document.getElementById('battleUI');
  if(!ui)return;
  const m=MONSTERS[S.mi];
  const mpc=Math.max(0,S.mhp/m.maxHp*100),ppc=Math.max(0,S.php);
  const mc=hpCol(mpc),pc=hpCol(ppc);
  const word=S.sel.map(id=>{const t=S.tiles.find(t=>t.id===id);return t?t.letter:''}).join('');
  const wl=word.toLowerCase();
  const valid=word.length>=3&&W.has(wl)&&canMake(wl,m.tiles);
  const already=S.used.has(wl);
  const d=valid&&!already?dmg(word.length):0;
  const tv=word.length>=3?tier(word.length):null;
  const tiles=S.tiles.map(t=>{
    const sel=S.sel.includes(t.id);
    return`<button class="tile${sel?' sel':''}" data-a="tile" data-p="${t.id}">${t.letter}</button>`;
  }).join('');
  const slots=S.sel.map(id=>{const t=S.tiles.find(t=>t.id===id);return t?`<span class="lslot">${t.letter}</span>`:''}).join('');
  let preview='';
  if(word.length>=3){
    if(already)preview=`<span style="margin-left:auto;font-size:11px;color:#ef4444;font-family:Cinzel,serif;font-weight:600">USED</span>`;
    else if(!W.has(wl))preview=`<span style="margin-left:auto;font-size:11px;color:#44405a;font-family:Cinzel,serif">?</span>`;
    else preview=`<span style="margin-left:auto;font-size:11px;font-family:Cinzel,serif;font-weight:700" class="${tv.c}">${tv.t} ${d}dmg</span>`;
  }
  const dots=MONSTERS.map((_,i)=>`<div class="dot" style="width:${i===S.mi?22:7}px;background:${i<S.mi?'#22c55e':i===S.mi?m.acc:'#2a2545'}"></div>`).join('');
  const logHTML=S.log.slice(0,2).map((l,i)=>`<div class="logline" style="color:${i===0?'#ddd6fe':'#4a4570'};font-size:${i===0?12:11}px">${l}</div>`).join('');
  const comboTag=S.combo>=2?`<span style="color:#f59e0b;font-family:Cinzel,serif;font-size:11px;margin-left:10px">🔥 ×${S.combo}</span>`:'';
  ui.innerHTML=`
    <div class="mrow">
      <div><div class="mname" style="color:${m.acc}">${m.name}</div><div class="msub">${m.sub}</div></div>
      <div class="hplabel">HP ${S.mhp} / ${m.maxHp}</div>
    </div>
    <div class="hpt"><div class="hpf" style="width:${mpc}%;background:${mc};box-shadow:0 0 10px ${mc}"></div></div>
    <div class="atk-track"><div class="atk-fill" id="atkb" style="width:0%"></div></div>
    <div class="arena" id="arena" style="--ms:rgba(${m.glow},.6);--mg:rgba(${m.glow},.4)">
      <div class="sprite ${m.sclass}" id="sprite">${getSprite(S.mi,false)}</div>
    </div>
    <div class="dots">${dots}</div>
    <div id="pbar" class="card${S.phurt?' phurt':''}" style="margin-bottom:7px">
      <div style="display:flex;justify-content:space-between;font-size:12px;font-weight:600;margin-bottom:4px">
        <span style="color:#c4b5fd">⚔ Wizard</span>
        <span style="color:${pc}">${S.php} / 100 HP</span>
      </div>
      <div class="hpt"><div class="hpf" style="width:${ppc}%;background:${pc};box-shadow:0 0 8px ${pc}"></div></div>
    </div>
    <div class="card" style="margin-bottom:7px;min-height:46px">${logHTML}</div>
    <div class="card wordzone${word.length>0?' active':''}" style="margin-bottom:7px">
      ${word.length===0?`<span style="color:#2d2a48;font-style:italic;font-size:13px">Tap letters to build a spell…</span>`:slots}
      ${preview}
    </div>
    <div class="tgrid">${tiles}</div>
    <div style="color:#3a3560;font-size:10px;text-align:center;margin-bottom:8px;font-family:Cinzel,serif;letter-spacing:.4px">${m.hint}${comboTag}</div>
    <div class="btn-row">
      <button class="btn-clear" data-a="clear">↩ Clear</button>
      <button class="btn-cast ${d>0?'ready':'off'}" data-a="cast">✦ Cast Spell</button>
    </div>`;
}

function renderTransition(){
  const done=MONSTERS[S.mi];
  return `
  <div class="bg" style="background:radial-gradient(ellipse at 50% 40%,rgba(34,197,94,.22) 0%,#050410 70%)"></div>
  <div class="result-content">
    <div style="position:absolute;top:40px;left:60px;width:6px;height:6px;background:#fbbf24;border-radius:50%;box-shadow:0 0 14px #fbbf24;animation:sparkle 1.4s ease-in-out infinite"></div>
    <div style="position:absolute;top:80px;right:50px;width:5px;height:5px;background:#4ade80;border-radius:50%;box-shadow:0 0 12px #4ade80;animation:sparkle 1.8s ease-in-out .3s infinite"></div>
    <div class="big-emoji" style="color:#4ade80">⚔️</div>
    <h2 style="color:#fbbf24">VICTORY!</h2>
    <p style="color:#4ade80;font-size:17px;font-weight:500">${done.name} defeated!</p>
    <p style="color:#fbbf24;font-size:14px;margin-top:4px">+${done.xp} XP · Total: ${S.txp}</p>
    <button class="scbtn" data-a="next">Next Battle →</button>
  </div>`;
}
function renderComplete(){
  return `
  <div class="bg" style="background:radial-gradient(ellipse at 50% 40%,rgba(251,191,36,.25) 0%,#050410 70%)"></div>
  <div class="result-content">
    <div style="position:absolute;top:30px;left:40px;width:6px;height:6px;background:#fbbf24;border-radius:50%;box-shadow:0 0 14px #fbbf24;animation:sparkle 1.4s ease-in-out infinite"></div>
    <div style="position:absolute;top:70px;right:60px;width:5px;height:5px;background:#f97316;border-radius:50%;box-shadow:0 0 12px #f97316;animation:sparkle 1.8s ease-in-out .3s infinite"></div>
    <div class="big-emoji" style="color:#fbbf24">🏆</div>
    <h2 style="color:#fbbf24">DUNGEON CLEARED</h2>
    <p>All 3 monsters defeated!</p>
    <p style="color:#a78bfa;font-size:15px">Final XP: ${S.txp}</p>
    <button class="scbtn" data-a="restart">↺ Play Again</button>
  </div>`;
}
function renderDefeat(){
  const m=MONSTERS[S.mi];
  return `
  <div class="bg" style="background:radial-gradient(ellipse at 50% 40%,rgba(239,68,68,.2) 0%,#050410 70%)"></div>
  <div class="result-content">
    <div class="big-emoji" style="color:#ef4444">💀</div>
    <h2 style="color:#ef4444">DEFEATED</h2>
    <p style="color:#94a3b8">The ${m.name} overwhelmed you.</p>
    <p style="color:#4a4570;font-size:13px">XP earned: ${S.txp}</p>
    <button class="scbtn" data-a="restart">↺ Try Again</button>
  </div>`;
}

// ── Boot ───────────────────────────────────────────────────────
showScreen('sBattle',buildBattleHTML());
renderBattle();
startTimers();
document.addEventListener('click',function firstClick(){
  ensureAudio();
  if(!muted&&S.phase==='battle')startMusic('battle');
  document.removeEventListener('click',firstClick);
},{once:true});
